script.inlineScript:
import { writeFileSync } from 'fs';
const REPO = 'Appsilon/mediforce';
const SKIP_LABELS = ['agent:attempting', 'agent:skip', 'agent:needs-info', 'agent:pr-open'];
const GO_LABEL = 'agent:go';
const H = { Accept: 'application/vnd.github+json', 'User-Agent': 'mediforce-fullstack-bot' };
async function gh(path) {
  const res = await fetch(`https://api.github.com${path}`, { headers: H });
  if (!res.ok) throw new Error(`GitHub ${res.status} ${path}: ${(await res.text()).slice(0, 200)}`);
  return res.json();
}
try {
  const collected = [];
  for (let page = 1; page <= 5; page++) {
    const batch = await gh(`/repos/${REPO}/issues?state=open&per_page=100&page=${page}`);
    for (const i of batch) {
      if (i.pull_request) continue;                      // skip PRs (issues endpoint returns both)
      const labels = (i.labels || []).map((l) => (typeof l === 'string' ? l : l.name));
      if (labels.some((l) => SKIP_LABELS.includes(l))) continue;  // claimed / parked / done
      if (i.assignee) continue;                          // a human is on it
      collected.push({
        number: i.number,
        title: i.title,
        body: (i.body || '').slice(0, 4000),
        url: i.html_url,
        author: (i.user && i.user.login) || null,
        labels,
        hasGoLabel: labels.includes(GO_LABEL),
        comments: i.comments,
        createdAt: i.created_at,
      });
    }
    if (batch.length < 100) break;
  }
  // agent:go first, then oldest-first (FIFO fairness).
  collected.sort(
    (a, b) =>
      (b.hasGoLabel ? 1 : 0) - (a.hasGoLabel ? 1 : 0) ||
      new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime(),
  );
  const issues = collected.slice(0, 30);
  writeFileSync('/output/result.json', JSON.stringify({ count: issues.length, issues }));
  console.log(`fetch-candidates: ${issues.length} candidate issue(s): ${issues.map((x) => '#' + x.number).join(', ')}`);
} catch (err) {
  console.error('fetch-candidates crashed:', err && err.stack ? err.stack : String(err));
  process.exit(1);
}
